// Gather raw responses from all three Plausible calls
const aggregateRaw = $('Fetch Aggregate Traffic').first().json;
const sourcesRaw = $('Fetch Traffic Sources').first().json;
const pagesRaw = $('Fetch Top Pages').first().json;

// --- Parse aggregate metrics ---
const agg = aggregateRaw.results || {};
const visitors = (agg.visitors || {}).value || 0;
const pageviews = (agg.pageviews || {}).value || 0;
const bounceRate = (agg.bounce_rate || {}).value || 0;
const visitDuration = (agg.visit_duration || {}).value || 0;

// --- Classify traffic sources ---
const organicEngines = ['google', 'bing', 'duckduckgo', 'yahoo', 'baidu', 'yandex', 'ecosia'];
const socialPlatforms = ['twitter', 'x.com', 't.co', 'facebook', 'linkedin', 'reddit', 'instagram', 'youtube', 'tiktok', 'threads.net', 'mastodon', 'hacker news', 'producthunt'];

let trafficOrganic = 0;
let trafficDirect = 0;
let trafficSocial = 0;
let trafficReferral = 0;

const sources = sourcesRaw.results || [];
for (const src of sources) {
  const name = (src.source || '').toLowerCase();
  const count = src.visitors || 0;
  if (name === 'direct / none' || name === 'direct' || name === '') {
    trafficDirect += count;
  } else if (organicEngines.some(e => name.includes(e))) {
    trafficOrganic += count;
  } else if (socialPlatforms.some(s => name.includes(s))) {
    trafficSocial += count;
  } else {
    trafficReferral += count;
  }
}

// Combine social into referral for Knowledge Graph (social = referral channel)
const trafficReferralTotal = trafficSocial + trafficReferral;

// --- Top pages ---
const pages = (pagesRaw.results || []).slice(0, 10).map(p => ({
  page: p.page,
  visitors: p.visitors || 0,
  pageviews: p.pageviews || 0
}));

// --- Build source breakdown for report ---
const sourceBreakdown = sources.map(s => ({
  source: s.source || '(unknown)',
  visitors: s.visitors || 0
})).sort((a, b) => b.visitors - a.visitors);

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];

return [{
  json: {
    date: dateStr,
    traffic_total: visitors,
    traffic_organic: trafficOrganic,
    traffic_paid: 0,
    traffic_direct: trafficDirect,
    traffic_referral: trafficReferralTotal,
    traffic_social: trafficSocial,
    pageviews: pageviews,
    bounce_rate: bounceRate,
    avg_visit_duration: visitDuration,
    top_pages: pages,
    source_breakdown: sourceBreakdown,
    api_success: !!(aggregateRaw.results)
  }
}];

const d = $('Process Plausible Data').first().json;
const date = d.date;
const topPages = d.top_pages || [];
const sources = d.source_breakdown || [];

let report = `# Traffic Report - BayFlow - ${date}\n\n`;
report += `## Summary\n`;
report += `| Metric | Value |\n|--------|-------|\n`;
report += `| Total Visitors | ${d.traffic_total} |\n`;
report += `| Pageviews | ${d.pageviews} |\n`;
report += `| Bounce Rate | ${d.bounce_rate}% |\n`;
report += `| Avg Visit Duration | ${d.avg_visit_duration}s |\n`;
report += `\n`;

report += `## Traffic by Channel\n`;
report += `| Channel | Visitors |\n|---------|----------|\n`;
report += `| Organic | ${d.traffic_organic} |\n`;
report += `| Direct | ${d.traffic_direct} |\n`;
report += `| Social | ${d.traffic_social} |\n`;
report += `| Referral | ${d.traffic_referral - d.traffic_social} |\n`;
report += `| Paid | ${d.traffic_paid} |\n`;
report += `\n`;

if (sources.length > 0) {
  report += `## Source Breakdown\n`;
  report += `| Source | Visitors |\n|--------|----------|\n`;
  for (const s of sources.slice(0, 15)) {
    report += `| ${s.source} | ${s.visitors} |\n`;
  }
  report += `\n`;
}

if (topPages.length > 0) {
  report += `## Top Pages\n`;
  report += `| Page | Visitors | Pageviews |\n|------|----------|-----------|\n`;
  for (const p of topPages) {
    report += `| ${p.page} | ${p.visitors} | ${p.pageviews} |\n`;
  }
  report += `\n`;
}

report += `---\n*Generated by Analytics Tracker workflow at ${new Date().toISOString()}*\n`;

return [{ json: { report, date } }];
